const conciergeFieldList = () => {
  const out = [];
  CONCIERGE.forEach((s, si) => {
    if (s.checklist) out.push({ id: `${si}:list`, kind: "checklist" });
    else s.f.forEach((_, fi) => out.push({ id: `${si}:${fi}`, kind: "text" }));
  });
  return out;
};
const TOTAL_FIELDS = conciergeFieldList().length;
function profilePct(answers = {}) {
  let done = 0;
  conciergeFieldList().forEach((f) => {
    const v = answers[f.id];
    if (f.kind === "checklist") { if (Array.isArray(v) && v.length) done++; }
    else if (v && String(v).trim()) done++;
  });
  return Math.round((done / TOTAL_FIELDS) * 100);
}

/* ============================ Rental economics ============================ */
function derive(it) {
  const m = it.monthly != null ? it.monthly : it.daily != null ? it.daily * 30 : null;
  const days = daysBetween(it.startDate);
  const rtd = m != null && days != null ? (m * days) / 30 : null;
  const be = it.purchase != null && m ? it.purchase / m : null;
  let rec = "rent";
  if (it.purchase != null && m) rec = rtd != null && rtd >= it.purchase ? "buy" : be <= 3 ? "consider" : "rent";
  else if (m == null) rec = "none";
  return { m, days, rtd, be, rec };
}
const RENTAL_REC = { buy: { ...TONE.bad, label: "Buy — past break-even" }, consider: { ...TONE.warn, label: "Consider buying" }, rent: { ...TONE.ok, label: "Keep renting" }, none: { ...TONE.idle, label: "Needs rate" } };
const RENTAL_CATS = ["Mattress/Bed", "Oxygen/Respiratory", "Wound Care", "Mobility", "Other"];

/* ============================ Audit scheduling ============================ */
const PERIOD = { Weekly: 7, Monthly: 30, Quarterly: 90, Yearly: 365 };
function auditStatus(template, reviews) {
  const mine = reviews.filter((r) => r.templateId === template.id);
  if (!mine.length) return { key: "idle", label: "Not started", last: null, compliance: null };
  const last = mine.map((r) => r.date).sort().slice(-1)[0];
  const age = daysBetween(last);
  const period = PERIOD[template.frequency] || 30;
  const recent = mine.filter((r) => r.date === last);
  let yes = 0, tot = 0;
  recent.forEach((r) => r.entries.forEach((e) => Object.values(e.values || {}).forEach((v) => { if (v === "yes") { yes++; tot++; } else if (v === "no") tot++; })));
  const compliance = tot ? Math.round((yes / tot) * 100) : null;
  const over = age != null && age > period;
  return { key: over ? "bad" : "ok", label: over ? `Overdue (${age}d)` : `Done ${fmtDate(last)}`, last, compliance };
}

