// Build the in-memory data shape from flat records. Every row keeps its record id.
function recordsToData(records) {
  const data = { rentals: {}, concierge: { residents: [] }, reviews: {}, modules: {}, budget: {} };
  records.forEach((r) => {
    const row = { id: r.id, ...r.data };
    if (r.module === "rentals") (data.rentals[r.facility_id] ||= []).push(row);
    else if (r.module === "concierge") data.concierge.residents.push(row);
    else if (r.module === "reviews") (data.reviews[r.facility_id] ||= []).push(row);
    else if (r.module === "budget") (data.budget[r.facility_id] ||= []).push(row);
    else { (data.modules[r.module] ||= {}); (data.modules[r.module][r.facility_id] ||= {}); (data.modules[r.module][r.facility_id][r.collection] ||= []).push(row); }
  });
  return data;
}
