/* ============================ Rentals module ============================ */
function Rentals({ facility, data, update }) {
  const items = data.rentals[facility.id] || [];
  const [modal, setModal] = useState(null);
  const monthly = items.reduce((a, it) => a + (derive(it).m || 0), 0);
  const review = items.filter((it) => ["buy", "consider"].includes(derive(it).rec)).length;

  const save = async (item) => {
    try {
      if (item.id && items.some((x) => x.id === item.id)) { await updateRecord(item.id, stripId(item)); update((d) => { const a = d.rentals[facility.id] || []; const i = a.findIndex((x) => x.id === item.id); if (i >= 0) a[i] = item; }); }
      else { const id = await createRecord("rentals", "items", facility.id, stripId(item)); update((d) => { (d.rentals[facility.id] ||= []).push({ ...item, id }); }); }
    } catch { onErr(); }
  };
  const del = async (id) => { try { await deleteRecord(id); update((d) => { d.rentals[facility.id] = (d.rentals[facility.id] || []).filter((x) => x.id !== id); }); } catch { onErr(); } };

  return (
    <div>
      <SectionHead title="Equipment rentals" right={<AddBtn onClick={() => setModal({})}>Add item</AddBtn>}
        stats={[["Items", items.length], ["Monthly", money(monthly)], ["To review", review, review ? "bad" : "ok"]]} />
      {items.length === 0 ? <Empty text="No rentals tracked here yet." /> : (
        <Table head={["Resident", "Equipment", "Category", "Monthly", "To date", "Break-even", "Recommendation", ""]}>
          {[...items].sort((a, b) => ({ buy: 0, consider: 1, rent: 2, none: 3 }[derive(a).rec] - { buy: 0, consider: 1, rent: 2, none: 3 }[derive(b).rec])).map((it) => {
            const d = derive(it), r = RENTAL_REC[d.rec];
            return (
              <tr key={it.id} className="group" style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
                <Td><div className="font-medium">{it.resident || "—"}</div><div className="text-xs" style={{ color: BRAND.inkSoft }}>{it.room}</div></Td>
                <Td>{it.equipment}</Td><Td soft>{it.category}</Td>
                <Td right>{d.m != null ? money(d.m) : "—"}</Td><Td right>{d.rtd != null ? money(d.rtd) : "—"}</Td>
                <Td right soft>{d.be != null ? d.be.toFixed(1) + " mo" : "—"}</Td>
                <Td><Pill tone={r}>{r.label}</Pill></Td>
                <Td><RowActions onEdit={() => setModal(it)} onDelete={() => del(it.id)} /></Td>
              </tr>
            );
          })}
        </Table>
      )}
      {modal && <RentalModal item={modal} onClose={() => setModal(null)} onSave={(x) => { save(x); setModal(null); }} />}
    </div>
  );
}

function RentalModal({ item, onClose, onSave }) {
  const [f, setF] = useState({ id: item.id, resident: item.resident || "", room: item.room || "", status: item.status || "Active",
    equipment: item.equipment || "", category: item.category || "Mattress/Bed", startDate: item.startDate || "",
    daily: item.daily ?? "", monthly: item.monthly ?? "", purchase: item.purchase ?? "", comments: item.comments || "" });
  const set = (k, v) => setF((p) => ({ ...p, [k]: v }));
  const clean = { ...f, daily: num(f.daily), monthly: num(f.monthly), purchase: num(f.purchase), equipment: f.equipment.trim() };
  const d = derive(clean), r = RENTAL_REC[d.rec];
  return (
    <Modal title={item.id ? "Edit item" : "Add item"} onClose={onClose} wide>
      <Grid2><Field label="Resident"><In v={f.resident} on={(v) => set("resident", v)} autoFocus /></Field><Field label="Room"><In v={f.room} on={(v) => set("room", v)} /></Field></Grid2>
      <Field label="Equipment"><In v={f.equipment} on={(v) => set("equipment", v)} /></Field>
      <Grid2><Field label="Category"><Sel v={f.category} on={(v) => set("category", v)} options={RENTAL_CATS} /></Field>
        <Field label="Status"><Sel v={f.status} on={(v) => set("status", v)} options={["Active", "Pending Order", "Discontinued"]} /></Field></Grid2>
      <Grid2><Field label="Start date"><In type="date" v={f.startDate} on={(v) => set("startDate", v)} /></Field><div /></Grid2>
      <div className="grid grid-cols-3 gap-3"><Field label="Daily $"><In v={f.daily} on={(v) => set("daily", v)} /></Field>
        <Field label="Monthly $"><In v={f.monthly} on={(v) => set("monthly", v)} /></Field><Field label="Purchase $"><In v={f.purchase} on={(v) => set("purchase", v)} /></Field></div>
      <Field label="Comments"><In v={f.comments} on={(v) => set("comments", v)} /></Field>
      <div className="rounded-lg px-4 py-3 mb-4 flex items-center justify-between" style={{ background: BRAND.lineSoft }}>
        <span className="text-xs" style={{ color: BRAND.inkSoft }}>{d.days != null ? `${d.days} days out` : "No start date"} · to date {d.rtd != null ? money(d.rtd) : "—"}</span>
        <Pill tone={r}>{r.label}</Pill>
      </div>
      <SaveRow ok={!!clean.equipment} onClose={onClose} onSave={() => onSave(clean)} />
    </Modal>
  );
}

/* ============================ Concierge module ============================ */
function upcomingDates(residents, withinDays = 14) {
  const out = [];
  const now = new Date(); const soon = new Date(Date.now() + withinDays * 86400000);
  const check = (label, iso, resName, fId, kind) => {
    if (!iso) return; const d = new Date(iso + "T00:00:00"); if (isNaN(d)) return;
    const next = new Date(now.getFullYear(), d.getMonth(), d.getDate());
    if (next < now) next.setFullYear(now.getFullYear() + 1);
    if (next <= soon) out.push({ label, date: next, resName, fId, kind });
  };
  residents.forEach((r) => {
    r.dates.forEach((dt) => check(dt.label, dt.date, r.name, r.facilityId, "date"));
    if (r.followUp && !r.followUp.done && r.followUp.dueDate) { const d = new Date(r.followUp.dueDate + "T00:00:00"); if (d <= soon) out.push({ label: "30-day follow-up", date: d, resName: r.name, fId: r.facilityId, kind: "followup" }); }
  });
  return out.sort((a, b) => a.date - b.date);
}

function Concierge({ facility, data, update }) {
  const residents = data.concierge.residents.filter((r) => r.facilityId === facility.id);
  const [openId, setOpenId] = useState(null);
  const [modal, setModal] = useState(null);

  const addResident = async (name, room, admitDate) => {
    const rec = { facilityId: facility.id, name, room, admitDate, answers: {}, requests: [], dates: [], followUp: { dueDate: admitDate ? new Date(new Date(admitDate).getTime() + 30 * 86400000).toISOString().slice(0, 10) : "", done: false, answers: {} } };
    try { const id = await createRecord("concierge", "residents", facility.id, rec); update((d) => d.concierge.residents.push({ ...rec, id })); }
    catch { onErr(); }
  };

  if (openId) {
    const r = data.concierge.residents.find((x) => x.id === openId);
    if (r) return <ResidentProfile resident={r} onBack={() => setOpenId(null)} update={update} />;
  }

  const complete = residents.filter((r) => profilePct(r.answers) === 100).length;
  const open = residents.reduce((a, r) => a + r.requests.filter((q) => q.status !== "done").length, 0);
  const up = upcomingDates(residents);

  return (
    <div>
      <SectionHead title="Concierge — resident discovery" right={<AddBtn onClick={() => setModal("res")}>Add resident</AddBtn>}
        stats={[["Residents", residents.length], ["Profiles complete", `${complete}/${residents.length}`], ["Open requests", open, open ? "warn" : "ok"]]} />

      {up.length > 0 && (
        <div className="rounded-xl p-4 mb-4" style={{ background: TONE.tan.bg, border: `1px solid ${BRAND.tan}` }}>
          <div className="flex items-center gap-2 mb-2 text-sm font-medium" style={{ color: TONE.tan.fg }}><CalendarHeart size={15} /> Coming up</div>
          <div className="flex flex-wrap gap-x-6 gap-y-1 text-sm" style={{ color: BRAND.ink }}>
            {up.map((u, i) => <span key={i}>{u.label} — <b>{u.resName}</b> · {u.date.toLocaleDateString(undefined, { month: "short", day: "numeric" })}</span>)}
          </div>
        </div>
      )}

      {residents.length === 0 ? <Empty text="No residents yet. Add one to start building their concierge profile." /> : (
        <div className="grid sm:grid-cols-2 lg:grid-cols-3 gap-3">
          {residents.map((r) => {
            const pct = profilePct(r.answers);
            const tone = pct === 100 ? TONE.ok : pct > 0 ? TONE.warn : TONE.idle;
            const openReq = r.requests.filter((q) => q.status !== "done").length;
            return (
              <button key={r.id} onClick={() => setOpenId(r.id)} className="text-left rounded-xl p-4 hover:shadow-sm" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
                <div className="flex items-start justify-between"><div><div className="font-semibold">{r.name}</div><div className="text-xs" style={{ color: BRAND.inkSoft }}>{r.room || "—"}</div></div>
                  <span className="h-8 w-8 rounded-full flex items-center justify-center" style={{ background: BRAND.lineSoft }}><User size={15} style={{ color: BRAND.tanDeep }} /></span></div>
                <div className="mt-3 flex items-center justify-between text-xs"><span style={{ color: tone.fg }}>{pct}% profile</span>{openReq > 0 && <span style={{ color: TONE.warn.fg }}>{openReq} open</span>}</div>
                <div className="h-1.5 rounded-full mt-1" style={{ background: BRAND.lineSoft }}><div className="h-1.5 rounded-full" style={{ width: pct + "%", background: BRAND.tan }} /></div>
              </button>
            );
          })}
        </div>
      )}
      {modal === "res" && <AddResidentModal onClose={() => setModal(null)} onSave={(n, rm, ad) => { addResident(n, rm, ad); setModal(null); }} />}
    </div>
  );
}

function AddResidentModal({ onClose, onSave }) {
  const [name, setName] = useState(""), [room, setRoom] = useState(""), [admit, setAdmit] = useState(todayISO());
  return (
    <Modal title="Add resident" onClose={onClose}>
      <Field label="Name"><In v={name} on={setName} autoFocus /></Field>
      <Grid2><Field label="Room"><In v={room} on={setRoom} /></Field><Field label="Admit date"><In type="date" v={admit} on={setAdmit} /></Field></Grid2>
      <SaveRow ok={!!name.trim()} onClose={onClose} onSave={() => onSave(name.trim(), room.trim(), admit)} />
    </Modal>
  );
}

function ResidentProfile({ resident, onBack, update }) {
  const [tab, setTab] = useState("profile"); // profile | requests | dates
  const [editing, setEditing] = useState({}); // section index -> bool
  const set = (fieldId, val) => update((d) => { const r = d.concierge.residents.find((x) => x.id === resident.id); r.answers[fieldId] = val; });
  const pct = profilePct(resident.answers);

  // Persist the whole resident record (answers, requests, dates, follow-up) after edits settle.
  const snapshot = JSON.stringify(stripId(resident));
  const firstRef = useRef(true);
  useEffect(() => {
    if (firstRef.current) { firstRef.current = false; return; }
    const t = setTimeout(() => { updateRecord(resident.id, JSON.parse(snapshot)).catch(() => {}); }, 700);
    return () => clearTimeout(t);
  }, [snapshot]);

  return (
    <div>
      <button onClick={onBack} className="inline-flex items-center gap-1 text-sm mb-3" style={{ color: BRAND.inkSoft }}><ArrowLeft size={15} /> All residents</button>
      <div className="flex items-end justify-between flex-wrap gap-3 mb-4">
        <div><h2 className="text-2xl" style={{ fontFamily: SERIF }}>{resident.name}</h2><div className="text-sm" style={{ color: BRAND.inkSoft }}>{resident.room || "—"} · admitted {fmtDate(resident.admitDate)}</div></div>
        <div className="text-right"><div className="text-xl tabular-nums" style={{ fontFamily: SERIF, color: BRAND.tanDeep }}>{pct}%</div><div className="text-[10px] uppercase tracking-wider" style={{ color: BRAND.inkSoft }}>profile complete</div></div>
      </div>
      <div className="inline-flex gap-1 p-1 rounded-xl mb-5" style={{ background: BRAND.lineSoft }}>
        {[["profile", "Discovery profile"], ["requests", "Service requests"], ["dates", "Dates & follow-up"]].map(([k, l]) => (
          <button key={k} onClick={() => setTab(k)} className="px-3 py-1.5 rounded-lg text-sm" style={tab === k ? { background: BRAND.ink, color: "#fff" } : { color: BRAND.inkSoft }}>{l}</button>
        ))}
      </div>

      {tab === "profile" && (
        <div className="space-y-3">
          <p className="text-xs" style={{ color: BRAND.inkSoft }}>Reads as a summary — empty questions are hidden. Use the pencil on any section to fill it in or make changes.</p>
          {CONCIERGE.map((s, si) => (
            <ProfileSection key={si} s={s} si={si} answers={resident.answers}
              editing={!!editing[si]} onToggle={() => setEditing((e) => ({ ...e, [si]: !e[si] }))} set={set} />
          ))}
        </div>
      )}

      {tab === "requests" && <Requests resident={resident} update={update} />}
      {tab === "dates" && <DatesFollowup resident={resident} update={update} />}
    </div>
  );
}

function ProfileSection({ s, si, answers, editing, onToggle, set }) {
  const isChecklist = !!s.checklist;
  const selected = answers[`${si}:list`] || [];
  const hasContent = isChecklist
    ? selected.length > 0
    : s.f.some((_, fi) => { const v = answers[`${si}:${fi}`]; return v && String(v).trim(); });

  return (
    <div className="rounded-xl p-5" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
      <div className="flex items-center justify-between mb-3">
        <div className="font-semibold" style={{ fontFamily: SERIF, fontSize: 16 }}>{s.t}</div>
        <button onClick={onToggle} className="inline-flex items-center gap-1.5 text-xs px-2.5 py-1 rounded-lg"
          style={editing ? { background: BRAND.ink, color: "#fff" } : { color: BRAND.inkSoft, background: BRAND.lineSoft }}>
          {editing ? <><CheckCircle2 size={13} /> Done</> : <><Pencil size={12} /> Edit</>}
        </button>
      </div>

      {editing ? (
        isChecklist ? (
          <div className="flex flex-wrap gap-2">
            {s.checklist.map((opt) => {
              const on = selected.includes(opt);
              return <button key={opt} onClick={() => set(`${si}:list`, on ? selected.filter((x) => x !== opt) : [...selected, opt])}
                className="px-3 py-1.5 rounded-full text-sm" style={on ? { background: BRAND.tan, color: BRAND.ink } : { background: BRAND.lineSoft, color: BRAND.inkSoft }}>{opt}</button>;
            })}
          </div>
        ) : (
          <div className="grid sm:grid-cols-2 gap-3">
            {s.f.map((q, fi) => {
              const label = typeof q === "string" ? q : q.q; const long = typeof q === "object" && q.type === "long";
              return (
                <label key={fi} className={long ? "sm:col-span-2" : ""}>
                  <span className="block text-xs mb-1" style={{ color: BRAND.inkSoft }}>{label}</span>
                  {long ? <textarea rows={2} style={inpStyle} value={answers[`${si}:${fi}`] || ""} onChange={(e) => set(`${si}:${fi}`, e.target.value)} />
                    : <input style={inpStyle} value={answers[`${si}:${fi}`] || ""} onChange={(e) => set(`${si}:${fi}`, e.target.value)} />}
                </label>
              );
            })}
          </div>
        )
      ) : !hasContent ? (
        <button onClick={onToggle} className="text-sm" style={{ color: "#b0aa9e" }}>Not filled in yet — tap to add</button>
      ) : isChecklist ? (
        <div className="flex flex-wrap gap-1.5">
          {selected.map((opt) => <span key={opt} className="px-2.5 py-1 rounded-full text-sm" style={{ background: TONE.tan.bg, color: TONE.tan.fg }}>{opt}</span>)}
        </div>
      ) : (
        <div className="grid sm:grid-cols-2 gap-x-6 gap-y-3">
          {s.f.map((q, fi) => {
            const label = typeof q === "string" ? q : q.q; const long = typeof q === "object" && q.type === "long";
            const v = answers[`${si}:${fi}`];
            if (!v || !String(v).trim()) return null;
            return (
              <div key={fi} className={long ? "sm:col-span-2" : ""}>
                <div className="text-[11px] uppercase tracking-wider mb-0.5" style={{ color: BRAND.inkSoft }}>{label}</div>
                <div style={{ color: BRAND.ink, whiteSpace: long ? "pre-wrap" : "normal" }}>{v}</div>
              </div>
            );
          })}
        </div>
      )}
    </div>
  );
}

const REQ_STATUS = { open: TONE.warn, scheduled: TONE.tan, done: TONE.ok };
function Requests({ resident, update }) {
  const [text, setText] = useState("");
  const add = () => { if (!text.trim()) return; update((d) => d.concierge.residents.find((x) => x.id === resident.id).requests.push({ id: uid(), text: text.trim(), status: "open", date: todayISO() })); setText(""); };
  const cycle = (id) => update((d) => { const q = d.concierge.residents.find((x) => x.id === resident.id).requests.find((r) => r.id === id); q.status = q.status === "open" ? "scheduled" : q.status === "scheduled" ? "done" : "open"; });
  const del = (id) => update((d) => { const r = d.concierge.residents.find((x) => x.id === resident.id); r.requests = r.requests.filter((q) => q.id !== id); });
  return (
    <div className="rounded-xl p-5" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
      <div className="flex gap-2 mb-4"><input style={inpStyle} placeholder="New request (e.g. hair appointment, takeout, video call)…" value={text} onChange={(e) => setText(e.target.value)} onKeyDown={(e) => e.key === "Enter" && add()} />
        <button onClick={add} className="px-4 rounded-lg text-white text-sm shrink-0" style={{ background: BRAND.ink }}>Add</button></div>
      {resident.requests.length === 0 ? <div className="text-sm text-center py-6" style={{ color: BRAND.inkSoft }}>No requests yet.</div> :
        <div className="space-y-2">{resident.requests.map((q) => (
          <div key={q.id} className="flex items-center justify-between gap-3 py-1">
            <span>{q.text}</span>
            <div className="flex items-center gap-2 shrink-0">
              <button onClick={() => cycle(q.id)}><Pill tone={REQ_STATUS[q.status]}>{q.status}</Pill></button>
              <IconBtn danger onClick={() => del(q.id)}><Trash2 size={14} /></IconBtn>
            </div>
          </div>))}</div>}
      <p className="text-xs mt-3" style={{ color: BRAND.inkSoft }}>Tap a status to advance it: open → scheduled → done.</p>
    </div>
  );
}

function DatesFollowup({ resident, update }) {
  const [label, setLabel] = useState("Birthday"), [date, setDate] = useState("");
  const add = () => { if (!date) return; update((d) => d.concierge.residents.find((x) => x.id === resident.id).dates.push({ id: uid(), label, date })); setDate(""); };
  const del = (id) => update((d) => { const r = d.concierge.residents.find((x) => x.id === resident.id); r.dates = r.dates.filter((x) => x.id !== id); });
  const fu = resident.followUp || {};
  const setFU = (fn) => update((d) => fn(d.concierge.residents.find((x) => x.id === resident.id).followUp));
  return (
    <div className="space-y-4">
      <div className="rounded-xl p-5" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
        <div className="text-sm font-semibold mb-3" style={{ fontFamily: SERIF, fontSize: 16 }}>Dates to remember</div>
        <div className="flex flex-wrap gap-2 mb-3">
          <Sel v={label} on={setLabel} options={["Birthday", "Anniversary", "Veteran recognition", "Milestone"]} />
          <input type="date" style={{ ...inpStyle, width: "auto" }} value={date} onChange={(e) => setDate(e.target.value)} />
          <button onClick={add} className="px-4 rounded-lg text-white text-sm" style={{ background: BRAND.ink }}>Add</button>
        </div>
        {resident.dates.length === 0 ? <div className="text-sm" style={{ color: BRAND.inkSoft }}>None yet.</div> :
          <div className="space-y-1">{resident.dates.map((dt) => <div key={dt.id} className="flex items-center justify-between"><span>{dt.label} — {fmtDate(dt.date)}</span><IconBtn danger onClick={() => del(dt.id)}><Trash2 size={14} /></IconBtn></div>)}</div>}
      </div>
      <div className="rounded-xl p-5" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
        <div className="flex items-center justify-between mb-3"><div className="text-sm font-semibold" style={{ fontFamily: SERIF, fontSize: 16 }}>30-day follow-up</div>
          <label className="text-sm flex items-center gap-2" style={{ color: BRAND.inkSoft }}><input type="checkbox" checked={!!fu.done} onChange={(e) => setFU((f) => { f.done = e.target.checked; })} /> Done</label></div>
        <div className="text-xs mb-3" style={{ color: BRAND.inkSoft }}>Due {fmtDate(fu.dueDate)}</div>
        <div className="space-y-3">{FOLLOWUP_Qs.map((q, i) => (
          <label key={i} className="block"><span className="block text-xs mb-1" style={{ color: BRAND.inkSoft }}>{q}</span>
            <input style={inpStyle} value={(fu.answers || {})[i] || ""} onChange={(e) => setFU((f) => { f.answers = f.answers || {}; f.answers[i] = e.target.value; })} /></label>))}</div>
      </div>
    </div>
  );
}

/* ============================ Audits module ============================ */
function Audits({ facility, program, data, update }) {
  const templates = AUDITS[program];
  const reviews = (data.reviews[facility.id] || []).filter((r) => r.program === program);
  const [run, setRun] = useState(null);
  const [q, setQ] = useState("");
  const FREQS = ["All", "Weekly", "Monthly", "Quarterly"];
  const [freq, setFreq] = useState("All");

  const list = templates.filter((t) => (freq === "All" || t.frequency === freq) && t.name.toLowerCase().includes(q.toLowerCase()));
  const overdue = templates.filter((t) => auditStatus(t, reviews).key === "bad").length;

  const saveReview = async (review) => {
    const payload = { ...stripId(review), program, facilityId: facility.id };
    try { const id = await createRecord("reviews", program, facility.id, payload); update((d) => { (d.reviews[facility.id] ||= []).push({ ...payload, id }); }); }
    catch { onErr(); }
  };

  if (run) return <RunAudit template={run} onBack={() => setRun(null)} onSave={(rev) => { saveReview(rev); setRun(null); }} />;

  return (
    <div>
      <SectionHead title={program === "clinical" ? "Clinical audits" : "Operations audits"}
        stats={[["Audit types", templates.length], ["Overdue", overdue, overdue ? "bad" : "ok"], ["Logged", reviews.length]]} />
      <div className="flex flex-wrap items-center gap-2 mb-3">
        <div className="flex gap-1">{FREQS.map((fq) => <button key={fq} onClick={() => setFreq(fq)} className="px-3 py-1.5 rounded-full text-sm" style={freq === fq ? { background: BRAND.ink, color: "#fff" } : { background: BRAND.card, color: BRAND.inkSoft, border: `1px solid ${BRAND.line}` }}>{fq}</button>)}</div>
        <div className="relative flex-1 min-w-[160px]"><Search size={15} className="absolute left-3 top-1/2 -translate-y-1/2" style={{ color: "#b3ada1" }} />
          <input style={{ ...inpStyle, paddingLeft: 34 }} placeholder="Search audits…" value={q} onChange={(e) => setQ(e.target.value)} /></div>
      </div>
      <div className="rounded-xl overflow-hidden" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
        <Table head={["Audit", "Frequency", "Criteria", "Status", "Compliance", ""]} flush>
          {list.map((t) => {
            const s = auditStatus(t, reviews); const tone = TONE[s.key];
            return (
              <tr key={t.id} style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
                <Td><span className="font-medium">{t.name}</span></Td>
                <Td soft>{t.frequency}</Td><Td soft>{t.fields.length}</Td>
                <Td><Pill tone={tone}>{s.label}</Pill></Td>
                <Td>{s.compliance == null ? <span style={{ color: "#c4beb2" }}>—</span> : <span className="tabular-nums" style={{ color: s.compliance >= 90 ? TONE.ok.fg : s.compliance >= 75 ? TONE.warn.fg : TONE.bad.fg }}>{s.compliance}%</span>}</Td>
                <Td><button onClick={() => setRun(t)} className="text-sm px-3 py-1.5 rounded-lg" style={{ background: BRAND.lineSoft, color: BRAND.ink }}>Log review</button></Td>
              </tr>
            );
          })}
        </Table>
      </div>
    </div>
  );
}

function RunAudit({ template, onBack, onSave }) {
  const [date, setDate] = useState(todayISO());
  const [entries, setEntries] = useState([blankEntry(template)]);
  function blankEntry(t) { return { id: uid(), label: "", values: {} }; }
  const setVal = (ei, fi, v) => setEntries((es) => es.map((e, i) => i === ei ? { ...e, values: { ...e.values, [fi]: e.values[fi] === v ? undefined : v } } : e));
  const setLabel = (ei, v) => setEntries((es) => es.map((e, i) => i === ei ? { ...e, label: v } : e));

  let yes = 0, tot = 0;
  entries.forEach((e) => Object.values(e.values).forEach((v) => { if (v === "yes") { yes++; tot++; } else if (v === "no") tot++; }));
  const compliance = tot ? Math.round((yes / tot) * 100) : null;

  return (
    <div>
      <button onClick={onBack} className="inline-flex items-center gap-1 text-sm mb-3" style={{ color: BRAND.inkSoft }}><ArrowLeft size={15} /> Audit list</button>
      <div className="flex items-end justify-between flex-wrap gap-3 mb-4">
        <div><h2 className="text-2xl" style={{ fontFamily: SERIF }}>{template.name}</h2><div className="text-sm" style={{ color: BRAND.inkSoft }}>{template.frequency} · {template.fields.length} criteria</div></div>
        <div className="flex items-center gap-3"><label className="text-sm" style={{ color: BRAND.inkSoft }}>Date <input type="date" style={{ ...inpStyle, width: "auto", display: "inline-block", marginLeft: 6 }} value={date} onChange={(e) => setDate(e.target.value)} /></label>
          {compliance != null && <Pill tone={compliance >= 90 ? TONE.ok : compliance >= 75 ? TONE.warn : TONE.bad}>{compliance}% compliant</Pill>}</div>
      </div>
      <div className="space-y-3">
        {entries.map((e, ei) => (
          <div key={e.id} className="rounded-xl p-4" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
            <div className="flex items-center gap-2 mb-3">
              <input style={inpStyle} placeholder={template.label || "Resident / line"} value={e.label} onChange={(ev) => setLabel(ei, ev.target.value)} />
              {entries.length > 1 && <IconBtn danger onClick={() => setEntries((es) => es.filter((_, i) => i !== ei))}><Trash2 size={15} /></IconBtn>}
            </div>
            <div className="grid sm:grid-cols-2 gap-x-6 gap-y-2">
              {template.fields.map((field, fi) => (
                <div key={fi} className="flex items-center justify-between gap-2 text-sm">
                  <span style={{ color: BRAND.inkSoft }}>{field}</span>
                  <div className="flex gap-1 shrink-0">
                    {["yes", "no", "na"].map((v) => (
                      <button key={v} onClick={() => setVal(ei, fi, v)} className="px-2 py-0.5 rounded text-xs uppercase"
                        style={e.values[fi] === v ? { background: v === "yes" ? TONE.ok.dot : v === "no" ? TONE.bad.dot : TONE.idle.dot, color: "#fff" } : { background: BRAND.lineSoft, color: BRAND.inkSoft }}>{v}</button>
                    ))}
                  </div>
                </div>
              ))}
            </div>
          </div>
        ))}
      </div>
      <div className="flex items-center justify-between mt-4">
        <button onClick={() => setEntries((es) => [...es, blankEntry(template)])} className="inline-flex items-center gap-1.5 text-sm" style={{ color: BRAND.tanDeep }}><Plus size={15} /> Add another resident / line</button>
        <button onClick={() => onSave({ templateId: template.id, date, entries })} className="inline-flex items-center gap-1.5 px-5 py-2 rounded-lg text-white text-sm" style={{ background: BRAND.ink }}><Save size={15} /> Save review</button>
      </div>
    </div>
  );
}

/* ============================ Spend-Down Budget module ============================ */
const CHART = [
  ["Activities", "Activities Equipment", 0], ["Activities", "Activities Supplies", 0.15], ["Activities", "Concierge", 0], ["Activities", "Employee Benefits", 0],
  ["Dietary", "Covid Dietary Supplies", 0], ["Dietary", "Kitchen Equipment", 0], ["Dietary", "Kitchen Supplies", 0.65], ["Dietary", "Patient Food", 6.5], ["Dietary", "Small Kitchen Equipment", 0], ["Dietary", "Supplements", 0],
  ["Housekeeping", "Housekeeping", 0], ["Housekeeping", "Housekeeping Supplies", 0.65], ["Housekeeping", "Laundry", 0.32],
  ["Maintenance", "Maintenance Equipment", 0], ["Maintenance", "Maintenance Supplies", 0.1], ["Maintenance", "Maintenance Uniforms", 0],
  ["Medical", "Covid Supplies", 0], ["Medical", "Employee Uniforms", 0], ["Medical", "Enterals", 0], ["Medical", "Gloves", 0], ["Medical", "Incontinence", 1.15], ["Medical", "Medical Equipment", 0], ["Medical", "Medical Supplies", 1.43], ["Medical", "OTC Medications", 0.14], ["Medical", "Oxygen", 0], ["Medical", "Rehab Supplies", 0.1], ["Medical", "Respiratory Supplies", 0],
  ["Office", "Office Equipment", 0], ["Office", "Office Equipment Rental", 0], ["Office", "Office Supplies", 0.2], ["Office", "Software", 0],
].map(([dept, account, ppd]) => ({ dept, account, key: `${dept}|${account}`, ppd }));
const CHART_DEPTS = [...new Set(CHART.map((c) => c.dept))];
const daysInMonth = (ym) => { const [y, m] = ym.split("-").map(Number); return new Date(y, m, 0).getDate(); };
const monthLabel = (ym) => { const [y, m] = ym.split("-").map(Number); return new Date(y, m - 1, 1).toLocaleDateString(undefined, { month: "long", year: "numeric" }); };
const thisMonth = () => todayISO().slice(0, 7);
function newBudgetDoc(month) {
  return { month, adc: 0, days: daysInMonth(month), reviewDate: "", spent: {}, ppd: Object.fromEntries(CHART.map((c) => [c.key, c.ppd])) };
}
const lineBudget = (doc, c) => (Number(doc.ppd?.[c.key] ?? c.ppd) || 0) * (Number(doc.adc) || 0) * (Number(doc.days) || 0);
function budgetTotals(doc) {
  let budget = 0, spent = 0, over = 0;
  CHART.forEach((c) => { const b = lineBudget(doc, c); const s = Number(doc.spent?.[c.key]) || 0; budget += b; spent += s; if (s > b && (b > 0 || s > 0)) over++; });
  return { budget, spent, remaining: budget - spent, over, pct: budget ? spent / budget : 0 };
}

function Budget({ facility, data, update }) {
  const docs = (data.budget && data.budget[facility.id]) || [];
  const [sel, setSel] = useState(docs.length ? docs[docs.length - 1].id : null);
  const doc = docs.find((d) => d.id === sel) || docs[docs.length - 1] || null;

  // debounce-persist the active month's record on edits
  const snap = doc ? JSON.stringify(stripId(doc)) : "";
  const lastRef = useRef({ id: null, snap: null });
  useEffect(() => {
    if (!doc) return;
    if (lastRef.current.id !== doc.id) { lastRef.current = { id: doc.id, snap }; return; }
    if (lastRef.current.snap === snap) return;
    lastRef.current.snap = snap;
    const t = setTimeout(() => updateRecord(doc.id, JSON.parse(snap)).catch(() => {}), 700);
    return () => clearTimeout(t);
  }, [snap, doc?.id]);

  const addMonth = async (month) => {
    if (docs.some((x) => x.month === month)) { const ex = docs.find((x) => x.month === month); setSel(ex.id); return; }
    const docData = newBudgetDoc(month);
    try { const id = await createRecord("budget", month, facility.id, docData); update((d) => { (d.budget ||= {}); (d.budget[facility.id] ||= []); d.budget[facility.id].push({ ...docData, id }); }); setSel(id); }
    catch { onErr(); }
  };
  const setDoc = (fn) => update((d) => { const t = d.budget[facility.id].find((x) => x.id === doc.id); fn(t); });

  if (!doc) {
    return (
      <div>
        <SectionHead title="Spend-Down Budget" />
        <Empty text="No budget month started yet." />
        <div className="flex justify-center mt-3"><MonthStarter onAdd={addMonth} /></div>
      </div>
    );
  }

  const t = budgetTotals(doc);
  return (
    <div>
      <SectionHead title="Spend-Down Budget"
        right={<div className="flex items-center gap-2">
          <select value={doc.id} onChange={(e) => setSel(e.target.value)} style={{ ...inpStyle, width: "auto" }}>
            {docs.map((x) => <option key={x.id} value={x.id}>{monthLabel(x.month)}</option>)}
          </select>
          <MonthStarter onAdd={addMonth} compact />
        </div>}
        stats={[["Budget", money(t.budget)], ["Spent", money(t.spent), t.spent > t.budget ? "bad" : "ok"], ["Remaining", money(t.remaining), t.remaining < 0 ? "bad" : "ok"], ["Accounts over", t.over, t.over ? "bad" : "ok"]]} />

      <div className="rounded-xl p-4 mb-4 grid sm:grid-cols-3 gap-3" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
        <label><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Avg Daily Census</span>
          <input style={inpStyle} inputMode="decimal" value={doc.adc} onChange={(e) => setDoc((x) => { x.adc = e.target.value; })} /></label>
        <label><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Days in Month</span>
          <input style={inpStyle} inputMode="numeric" value={doc.days} onChange={(e) => setDoc((x) => { x.days = e.target.value; })} /></label>
        <label><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>% Spent</span>
          <div className="text-lg tabular-nums" style={{ fontFamily: SERIF, color: t.pct > 1 ? TONE.bad.fg : t.pct >= 0.9 ? TONE.warn.fg : TONE.ok.fg }}>{Math.round(t.pct * 100)}%</div></label>
      </div>

      <div className="rounded-xl overflow-hidden" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
        <div className="overflow-x-auto">
          <table className="w-full text-sm">
            <thead><tr style={{ background: BRAND.lineSoft, color: BRAND.inkSoft }} className="text-left text-[11px] uppercase tracking-wider">
              <th className="px-3 py-2.5 font-medium">Account</th><th className="px-3 py-2.5 font-medium text-right">PPD</th>
              <th className="px-3 py-2.5 font-medium text-right">Monthly Budget</th><th className="px-3 py-2.5 font-medium text-right">Spent</th>
              <th className="px-3 py-2.5 font-medium text-right">Remaining</th><th className="px-3 py-2.5 font-medium text-right">% Spent</th><th className="px-3 py-2.5 font-medium">Status</th>
            </tr></thead>
            <tbody>
              {CHART_DEPTS.map((dept) => {
                const lines = CHART.filter((c) => c.dept === dept);
                const sub = { b: 0, s: 0 };
                const rows = lines.map((c) => {
                  const b = lineBudget(doc, c); const s = Number(doc.spent?.[c.key]) || 0; sub.b += b; sub.s += s;
                  const over = s > b && (b > 0 || s > 0); const pct = b ? s / b : 0;
                  const tone = over ? TONE.bad : pct >= 0.9 ? TONE.warn : s > 0 ? TONE.ok : TONE.idle;
                  return (
                    <tr key={c.key} style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
                      <td className="px-3 py-2 pl-6">{c.account}</td>
                      <td className="px-3 py-2 text-right"><input style={{ ...inpStyle, width: 70, padding: "4px 8px", textAlign: "right" }} value={doc.ppd?.[c.key] ?? c.ppd} onChange={(e) => setDoc((x) => { (x.ppd ||= {})[c.key] = e.target.value; })} /></td>
                      <td className="px-3 py-2 text-right tabular-nums" style={{ color: BRAND.inkSoft }}>{money(b)}</td>
                      <td className="px-3 py-2 text-right"><input style={{ ...inpStyle, width: 90, padding: "4px 8px", textAlign: "right" }} value={doc.spent?.[c.key] ?? ""} onChange={(e) => setDoc((x) => { (x.spent ||= {})[c.key] = e.target.value; })} /></td>
                      <td className="px-3 py-2 text-right tabular-nums" style={{ color: (b - s) < 0 ? TONE.bad.fg : BRAND.ink }}>{money(b - s)}</td>
                      <td className="px-3 py-2 text-right tabular-nums" style={{ color: BRAND.inkSoft }}>{b ? Math.round(pct * 100) + "%" : "—"}</td>
                      <td className="px-3 py-2"><Pill tone={tone}>{over ? "Over" : pct >= 0.9 ? "Watch" : s > 0 ? "OK" : "—"}</Pill></td>
                    </tr>
                  );
                });
                return <FragmentDept key={dept} dept={dept} rows={rows} sub={sub} />;
              })}
              <tr style={{ borderTop: `2px solid ${BRAND.line}`, background: BRAND.lineSoft }}>
                <td className="px-3 py-3 font-semibold" style={{ fontFamily: SERIF }}>Center total</td><td />
                <td className="px-3 py-3 text-right tabular-nums font-semibold">{money(t.budget)}</td>
                <td className="px-3 py-3 text-right tabular-nums font-semibold">{money(t.spent)}</td>
                <td className="px-3 py-3 text-right tabular-nums font-semibold" style={{ color: t.remaining < 0 ? TONE.bad.fg : BRAND.ink }}>{money(t.remaining)}</td>
                <td className="px-3 py-3 text-right tabular-nums font-semibold">{Math.round(t.pct * 100)}%</td><td />
              </tr>
            </tbody>
          </table>
        </div>
      </div>
      <p className="text-xs mt-2" style={{ color: BRAND.inkSoft }}>Monthly Budget = PPD × Avg Daily Census × Days. Enter PPD rates and actual Spent; budgets, overages, and the roll-up calculate automatically.</p>
    </div>
  );
}

