/* ============================ Login ============================ */
function Login({ onLogin }) {
  const [mode, setMode] = useState("signin");
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);
  const [sent, setSent] = useState(false);
  const submit = async () => {
    if (!email || !password) return;
    setBusy(true); setErr("");
    try { const r = await api("/api/login", "POST", { email, password }); onLogin(r.token, r.user); }
    catch (e) { setErr(/too many/i.test(e.message) ? e.message : "That email and password didn’t match."); }
    finally { setBusy(false); }
  };
  const sendReset = async () => {
    if (!email) return;
    setBusy(true); setErr("");
    try { await api("/api/forgot", "POST", { email }); setSent(true); }
    catch (e) { setErr(/too many/i.test(e.message) ? e.message : "Something went wrong."); }
    finally { setBusy(false); }
  };
  const Head = (
    <div className="flex flex-col items-center text-center mb-6">
      <img src={EMINENT_LOGO} alt="Eminent Care Group" className="h-20 w-auto object-contain" />
      <div className="text-[11px] uppercase tracking-[0.22em] mt-3" style={{ color: BRAND.tanDeep }}>Operations Platform</div>
    </div>
  );
  if (mode === "forgot") {
    return (
      <div className="min-h-screen flex items-center justify-center px-4" style={{ background: BRAND.paper, color: BRAND.ink }}>
        <div className="w-full max-w-sm">{Head}
          <div className="rounded-2xl p-6" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
            {sent ? (
              <p className="text-sm" style={{ color: BRAND.inkSoft }}>If an account exists for <span style={{ color: BRAND.ink }}>{email}</span>, a reset link is on its way. Check your inbox and spam. It expires in 1 hour.</p>
            ) : (<>
              <div className="text-sm mb-3" style={{ fontFamily: SERIF }}>Reset your password</div>
              <label className="block mb-4"><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Email</span>
                <input style={inpStyle} type="email" value={email} autoFocus onChange={(e) => setEmail(e.target.value)} onKeyDown={(e) => e.key === "Enter" && sendReset()} /></label>
              {err && <div className="text-xs mb-3" style={{ color: TONE.bad.fg }}>{err}</div>}
              <button onClick={sendReset} disabled={busy} className="w-full rounded-lg py-2.5 text-sm text-white" style={{ background: BRAND.ink, opacity: busy ? 0.6 : 1 }}>{busy ? "Sending…" : "Send reset link"}</button>
            </>)}
          </div>
          <button onClick={() => { setMode("signin"); setSent(false); setErr(""); }} className="block mx-auto text-xs mt-4 underline" style={{ color: BRAND.inkSoft }}>Back to sign in</button>
        </div>
      </div>
    );
  }
  return (
    <div className="min-h-screen flex items-center justify-center px-4" style={{ background: BRAND.paper, color: BRAND.ink }}>
      <div className="w-full max-w-sm">{Head}
        <div className="rounded-2xl overflow-hidden" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
          <div className="px-5 py-3 text-xs flex items-center gap-2" style={{ background: TONE.bad.bg, color: TONE.bad.fg }}>
            <AlertTriangle size={14} /> Private system — authorized users only. Activity is monitored.
          </div>
          <div className="p-5">
            <label className="block mb-3"><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Email</span>
              <input style={inpStyle} type="email" value={email} autoFocus onChange={(e) => setEmail(e.target.value)} onKeyDown={(e) => e.key === "Enter" && submit()} /></label>
            <label className="block mb-4"><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Password</span>
              <input style={inpStyle} type="password" value={password} onChange={(e) => setPassword(e.target.value)} onKeyDown={(e) => e.key === "Enter" && submit()} /></label>
            {err && <div className="text-xs mb-3" style={{ color: TONE.bad.fg }}>{err}</div>}
            <button onClick={submit} disabled={busy} className="w-full rounded-lg py-2.5 text-sm text-white" style={{ background: BRAND.ink, opacity: busy ? 0.6 : 1 }}>{busy ? "Signing in…" : "Sign in"}</button>
            <button onClick={() => { setMode("forgot"); setErr(""); }} className="block mx-auto text-xs mt-3 underline" style={{ color: BRAND.inkSoft }}>Forgot password?</button>
          </div>
        </div>
        <p className="text-center text-xs mt-4" style={{ color: BRAND.inkSoft }}>Corporate sees every facility. Each facility sees only its own.</p>
      </div>
    </div>
  );
}

/* ============================ Reset password ============================ */
function ResetPassword({ token }) {
  const [password, setPassword] = useState("");
  const [confirm, setConfirm] = useState("");
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);
  const [done, setDone] = useState(false);
  const submit = async () => {
    if (password.length < 8) { setErr("Password must be at least 8 characters."); return; }
    if (password !== confirm) { setErr("The two passwords don’t match."); return; }
    setBusy(true); setErr("");
    try { await api("/api/reset", "POST", { token, password }); setDone(true); }
    catch (e) { setErr(e.message || "This reset link is invalid or expired."); }
    finally { setBusy(false); }
  };
  return (
    <div className="min-h-screen flex items-center justify-center px-4" style={{ background: BRAND.paper, color: BRAND.ink }}>
      <div className="w-full max-w-sm">
        <div className="flex flex-col items-center text-center mb-6"><img src={EMINENT_LOGO} alt="Eminent Care Group" className="h-20 w-auto object-contain" /></div>
        <div className="rounded-2xl p-6" style={{ background: BRAND.card, border: `1px solid ${BRAND.line}` }}>
          {done ? (<>
            <p className="text-sm mb-4" style={{ color: BRAND.inkSoft }}>Your password has been changed. You can sign in with it now.</p>
            <button onClick={() => { window.location.href = window.location.pathname; }} className="w-full rounded-lg py-2.5 text-sm text-white" style={{ background: BRAND.ink }}>Go to sign in</button>
          </>) : (<>
            <div className="text-sm mb-3" style={{ fontFamily: SERIF }}>Choose a new password</div>
            <label className="block mb-3"><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>New password</span>
              <input style={inpStyle} type="password" value={password} autoFocus onChange={(e) => setPassword(e.target.value)} /></label>
            <label className="block mb-4"><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Confirm password</span>
              <input style={inpStyle} type="password" value={confirm} onChange={(e) => setConfirm(e.target.value)} onKeyDown={(e) => e.key === "Enter" && submit()} /></label>
            {err && <div className="text-xs mb-3" style={{ color: TONE.bad.fg }}>{err}</div>}
            <button onClick={submit} disabled={busy} className="w-full rounded-lg py-2.5 text-sm text-white" style={{ background: BRAND.ink, opacity: busy ? 0.6 : 1 }}>{busy ? "Saving…" : "Set new password"}</button>
          </>)}
        </div>
      </div>
    </div>
  );
}

/* ============================ Login manager (admin) ============================ */
const genPw = () => Math.random().toString(36).slice(2, 6) + "-" + Math.random().toString(36).slice(2, 6);
const ROLE_LABEL = { admin: "Administrator", corporate: "Corporate", facility: "Facility" };
function UserManager({ facilities, meId, onClose }) {
  const [users, setUsers] = useState(null);
  const [err, setErr] = useState("");
  const [busy, setBusy] = useState(false);
  const [created, setCreated] = useState(null);
  const [resetId, setResetId] = useState(null);
  const [resetPw, setResetPw] = useState("");
  const [form, setForm] = useState({ email: "", role: "facility", facilityId: facilities[0]?.id || "", password: genPw() });
  useEffect(() => { (async () => { try { setUsers(await api("/api/users")); } catch (e) { setErr(e.message); } })(); }, []);
  const set = (k, v) => setForm((p) => ({ ...p, [k]: v }));
  const add = async () => {
    setErr(""); setBusy(true);
    try {
      const u = await api("/api/users", "POST", { email: form.email.trim(), role: form.role, facilityId: form.role === "facility" ? form.facilityId : null, password: form.password });
      setUsers((l) => [u, ...(l || [])]); setCreated({ email: u.email, password: form.password });
      setForm({ email: "", role: "facility", facilityId: facilities[0]?.id || "", password: genPw() });
    } catch (e) { setErr(e.message); } finally { setBusy(false); }
  };
  const doReset = async (id, email) => {
    setBusy(true); setErr("");
    try { await api(`/api/users/${id}/password`, "PATCH", { password: resetPw }); setCreated({ email, password: resetPw }); setResetId(null); setResetPw(""); }
    catch (e) { setErr(e.message); } finally { setBusy(false); }
  };
  const remove = async (id) => { setBusy(true); setErr(""); try { await api(`/api/users/${id}`, "DELETE"); setUsers((l) => l.filter((x) => x.id !== id)); } catch (e) { setErr(e.message); } finally { setBusy(false); } };
  return (
    <Modal title="Logins" onClose={onClose} wide>
      <p className="text-sm mb-4" style={{ color: BRAND.inkSoft }}>Administrators see everything and manage logins. Corporate sees everything but not this screen. A facility login sees only its own building.</p>
      <div className="rounded-xl p-4 mb-4" style={{ border: `1px solid ${BRAND.line}` }}>
        <div className="text-sm mb-3" style={{ fontFamily: SERIF }}>Add a login</div>
        <label className="block mb-2"><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Email</span>
          <input style={inpStyle} type="email" value={form.email} onChange={(e) => set("email", e.target.value)} placeholder="name@eminentcare.com" /></label>
        <label className="block mb-2"><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Access level</span>
          <select style={inpStyle} value={form.role} onChange={(e) => set("role", e.target.value)}>
            <option value="facility">Facility — one building</option>
            <option value="corporate">Corporate — all buildings, no login manager</option>
            <option value="admin">Administrator — all buildings + manages logins</option>
          </select></label>
        {form.role === "facility" && (
          <label className="block mb-2"><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Facility</span>
            <select style={inpStyle} value={form.facilityId} onChange={(e) => set("facilityId", e.target.value)}>{facilities.map((f) => <option key={f.id} value={f.id}>{f.name}</option>)}</select></label>
        )}
        <label className="block mb-3"><span className="block text-[11px] uppercase tracking-wider mb-1" style={{ color: BRAND.inkSoft }}>Temporary password</span>
          <div className="flex gap-2"><input style={inpStyle} value={form.password} onChange={(e) => set("password", e.target.value)} />
            <button onClick={() => set("password", genPw())} className="shrink-0 px-3 rounded-lg text-xs" style={{ border: `1px solid ${BRAND.line}`, color: BRAND.inkSoft }}>New</button></div></label>
        {err && <div className="text-xs mb-2" style={{ color: TONE.bad.fg }}>{err}</div>}
        <div className="flex justify-end"><button disabled={busy} onClick={add} className="inline-flex items-center gap-1.5 px-4 py-2 rounded-lg text-sm text-white" style={{ background: BRAND.ink, opacity: busy ? 0.6 : 1 }}><Plus size={15} /> Create login</button></div>
        {created && <div className="mt-3 rounded-lg px-4 py-3 text-sm" style={{ background: TONE.good.bg, color: TONE.good.fg }}>Share once, then have them change it: <b>{created.email}</b> · password <span className="font-mono">{created.password}</span> <button onClick={() => setCreated(null)} className="underline ml-2">dismiss</button></div>}
      </div>
      <div className="rounded-xl overflow-hidden" style={{ border: `1px solid ${BRAND.line}` }}>
        {users === null ? <div className="px-4 py-5 text-sm" style={{ color: BRAND.inkSoft }}>Loading…</div>
          : users.map((u) => (
            <div key={u.id} className="px-4 py-3 flex items-center justify-between gap-3" style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
              <div className="min-w-0"><div className="text-sm truncate">{u.email}{u.id === meId && <span className="text-[11px] ml-2" style={{ color: BRAND.inkSoft }}>(you)</span>}</div>
                <div className="text-[11px] uppercase tracking-wider mt-0.5" style={{ color: BRAND.inkSoft }}>{ROLE_LABEL[u.role]}{u.role === "facility" && u.facilityName ? ` · ${u.facilityName}` : ""}</div></div>
              {resetId === u.id ? (
                <div className="flex items-center gap-2 shrink-0"><input style={{ ...inpStyle, width: 140 }} value={resetPw} onChange={(e) => setResetPw(e.target.value)} placeholder="new password" />
                  <button onClick={() => setResetPw(genPw())} className="px-2 rounded-lg text-xs" style={{ border: `1px solid ${BRAND.line}`, color: BRAND.inkSoft }}>New</button>
                  <button disabled={resetPw.length < 8} onClick={() => doReset(u.id, u.email)} className="px-3 py-1.5 rounded-lg text-xs text-white" style={{ background: BRAND.ink, opacity: resetPw.length < 8 ? 0.5 : 1 }}>Save</button>
                  <button onClick={() => { setResetId(null); setResetPw(""); }} className="text-xs" style={{ color: BRAND.inkSoft }}>Cancel</button></div>
              ) : (
                <div className="flex items-center gap-1 shrink-0">
                  <button onClick={() => { setResetId(u.id); setResetPw(genPw()); }} className="inline-flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs" style={{ color: BRAND.inkSoft }}><KeyRound size={14} /> Reset</button>
                  {u.id !== meId && <button onClick={() => remove(u.id)} className="inline-flex items-center gap-1 px-2.5 py-1.5 rounded-lg text-xs" style={{ color: TONE.bad.fg }}><Trash2 size={14} /> Remove</button>}
                </div>
              )}
            </div>
          ))}
      </div>
    </Modal>
  );
}

/* ============================ Activity log (admin, hidden) ============================ */
const ACTION_LABEL = {
  login: "Signed in", login_failed: "Failed sign-in", bootstrap: "Opened the app",
  create: "Added a record", update: "Edited a record", delete: "Deleted a record",
  user_create: "Created a login", user_reset_password: "Reset a password", user_delete: "Removed a login",
  password_reset_sent: "Reset link emailed", password_reset: "Password reset (self-service)",
};
function AuditLog({ onClose }) {
  const [rows, setRows] = useState(null);
  const [err, setErr] = useState("");
  const load = async () => { setErr(""); try { setRows(await api("/api/audit")); } catch (e) { setErr(e.message); } };
  useEffect(() => { load(); }, []);
  return (
    <Modal title="Activity log" onClose={onClose} wide>
      <p className="text-sm mb-3" style={{ color: BRAND.inkSoft }}>A running record of sign-ins and every change — newest first, most recent 200. Entries are only ever added.</p>
      {err && <div className="text-xs mb-2" style={{ color: TONE.bad.fg }}>{err}</div>}
      <div className="rounded-xl overflow-hidden" style={{ border: `1px solid ${BRAND.line}`, maxHeight: "60vh", overflowY: "auto" }}>
        {rows === null ? <div className="px-4 py-5 text-sm" style={{ color: BRAND.inkSoft }}>Loading…</div>
          : rows.length === 0 ? <div className="px-4 py-5 text-sm" style={{ color: BRAND.inkSoft }}>No activity yet.</div>
          : rows.map((r) => (
            <div key={r.id} className="px-4 py-2.5 flex items-start justify-between gap-3" style={{ borderTop: `1px solid ${BRAND.lineSoft}` }}>
              <div className="min-w-0"><div className="text-sm">{ACTION_LABEL[r.action] || r.action}{r.facilityName ? <span style={{ color: BRAND.inkSoft }}> · {r.facilityName}</span> : ""}</div>
                <div className="text-[12px] mt-0.5 truncate" style={{ color: BRAND.inkSoft }}>{r.email || "—"}{r.module ? ` · ${r.module}` : ""}</div></div>
              <div className="text-[11px] whitespace-nowrap shrink-0" style={{ color: BRAND.inkSoft }}>{new Date(r.at).toLocaleString()}</div>
            </div>
          ))}
      </div>
    </Modal>
  );
}
